import TomSelect from"../../tom-select.js";import{getDom}from"../../vanilla.js";TomSelect.define("clear_button",function(t){var e=this;t=Object.assign({className:"clear-button",title:"Clear All",html:t=>`<div class="${t.className}" title="${t.title}">&times;</div>`},t),e.hook("after","setup",()=>{var l=getDom(t.html(t));l.addEventListener("click",t=>{for(;e.items.length>0;)e.removeItem(e.items[0]);t.preventDefault(),t.stopPropagation()}),e.control.appendChild(l)})});